class SAMLResponseValidator {
    private static final String SUCCESS_STATUS = "urn:oasis:names:tc:SAML:2.0:status:Success";
    private String expectedAudience;

    public SAMLResponseValidator(String expectedAudience) {
        this.expectedAudience = expectedAudience;
    }

    public void validate(SAMLResponse response) throws SAMLValidationException {
        if (response == null) {
            throw new SAMLValidationException("SAML response is null");
        }

        if (response.getDocument() == null) {
            throw new SAMLValidationException("SAML response document is null");
        }

        Element rootElement = response.getDocument().getDocumentElement();
        if (!"Response".equals(rootElement.getLocalName())) {
            throw new SAMLValidationException("Root element is not a Response");
        }

        if (response.getResponseId() == null || response.getResponseId().isEmpty()) {
            throw new SAMLValidationException("Response ID is missing");
        }

        if (response.getIssuer() == null || response.getIssuer().isEmpty()) {
            throw new SAMLValidationException("Issuer is missing");
        }

        if (!SUCCESS_STATUS.equals(response.getStatus())) {
            throw new SAMLValidationException("Response status is not Success: " + response.getStatus());
        }

        if (response.getAssertions().isEmpty()) {
            throw new SAMLValidationException("No assertions found in response");
        }

        for (SAMLAssertion assertion : response.getAssertions()) {
            validateAssertion(assertion);
        }
    }

    private void validateAssertion(SAMLAssertion assertion) throws SAMLValidationException {
        if (assertion.getAssertionId() == null || assertion.getAssertionId().isEmpty()) {
            throw new SAMLValidationException("Assertion ID is missing");
        }

        if (assertion.getSubject() == null || assertion.getSubject().isEmpty()) {
            throw new SAMLValidationException("Subject is missing in assertion");
        }

        Instant now = Instant.now();

        if (assertion.getNotBefore() != null && now.isBefore(assertion.getNotBefore())) {
            throw new SAMLValidationException("Assertion is not yet valid");
        }

        if (assertion.getNotOnOrAfter() != null && now.isAfter(assertion.getNotOnOrAfter())) {
            throw new SAMLValidationException("Assertion has expired");
        }

        if (expectedAudience != null && !expectedAudience.isEmpty()) {
            if (assertion.getAudience() == null || !expectedAudience.equals(assertion.getAudience())) {
                throw new SAMLValidationException("Audience restriction does not match expected audience");
            }
        }
    }
}

